insert into session_occurrences (activity_option_id, operator_id, starts_at, ends_at, capacity) select o.id, a.operator_id, gs, gs + interval '4 hours', 20 from activity_options o join activities a on a.id = o.activity_id cross join generate_series((current_date + 1)::timestamp + time '09:00', (current_date + 7)::timestamp + time '09:00', interval '1 day') gs where exists (select 1 from activity_option_prices p where p.activity_option_id = o.id);
